def run_research_then_summarise(question: str, tools: list) -> str:
    messages = [{"role": "user", "content": question}]

    # Research phase — tools allowed
    for _ in range(10):
        response = client.messages.create(
            model="claude-sonnet-4-6", max_tokens=4096,
            tools=tools,
            tool_choice={"type": "auto"},
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            break  # Model finished research naturally

        if response.stop_reason == "tool_use":
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    result = dispatch_tool(block.name, block.input)
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": result,
                    })
            messages.append({"role": "user", "content": tool_results})

    # Summarisation phase — force text, no more tool calls
    messages.append({"role": "user", "content": "Please summarise your findings concisely."})
    final = client.messages.create(
        model="claude-sonnet-4-6", max_tokens=1024,
        tools=tools,
        tool_choice={"type": "none"},   # ← no tools on this turn
        messages=messages,
    )
    return next(b.text for b in final.content if hasattr(b, "text"))

import anthropic, json
from concurrent.futures import ThreadPoolExecutor, as_completed

client = anthropic.Anthropic()

entity_extractor = {
    "name": "extract_entities",
    "description": "Extract named entities from text.",
    "input_schema": {
        "type": "object",
        "properties": {
            "people":        {"type": "array", "items": {"type": "string"}},
            "organisations": {"type": "array", "items": {"type": "string"}},
            "locations":     {"type": "array", "items": {"type": "string"}},
            "dates":         {"type": "array", "items": {"type": "string"}},
        },
        "required": ["people", "organisations", "locations", "dates"],
    },
}

def extract_entities(text: str) -> dict:
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=512,
        tools=[entity_extractor],
        tool_choice={"type": "tool", "name": "extract_entities"},
        messages=[{"role": "user", "content": text}],
    )
    tool_block = next(b for b in response.content if b.type == "tool_use")
    return tool_block.input

def batch_extract(documents: list[str], max_workers: int = 5) -> list[dict]:
    results = [None] * len(documents)
    with ThreadPoolExecutor(max_workers=max_workers) as pool:
        futures = {pool.submit(extract_entities, doc): i for i, doc in enumerate(documents)}
        for future in as_completed(futures):
            idx = futures[future]
            try:
                results[idx] = future.result()
            except Exception as exc:
                results[idx] = {"error": str(exc)}
    return results

