EXTRACTION_SYSTEM = """
You are a precise data extraction assistant. Extract information exactly
as it appears in the source text — do not infer, interpret, or add information
that is not explicitly stated. If a field is not present in the text, omit it
rather than guessing.
"""

resume_extractor = {
    "name": "extract_resume_data",
    "description": "Extract structured data from a resume or CV.",
    "input_schema": {
        "type": "object",
        "properties": {
            "full_name":        {"type": "string"},
            "email":            {"type": "string"},
            "phone":            {"type": "string"},
            "current_title":    {"type": "string"},
            "years_experience": {"type": "integer"},
            "skills":           {"type": "array", "items": {"type": "string"}},
            "education": {
                "type": "array",
                "items": {
                    "type": "object",
                    "properties": {
                        "degree":      {"type": "string"},
                        "institution": {"type": "string"},
                        "year":        {"type": "integer"},
                    },
                },
            },
        },
        "required": ["full_name"],
    },
}

def parse_resume(resume_text: str) -> dict:
    response = client.messages.create(
        model="claude-sonnet-4-6",
        max_tokens=1024,
        system=EXTRACTION_SYSTEM,
        tools=[resume_extractor],
        tool_choice={"type": "tool", "name": "extract_resume_data"},
        messages=[{"role": "user", "content": resume_text}],
    )
    tool_block = next(b for b in response.content if b.type == "tool_use")
    return tool_block.input

